function showContext() {
  console.log(this);
}

showContext();          // window (browser sloppy)
// "use strict";
// showContext();       // TypeError: Cannot read 'x' of undefined

// In TypeScript with --strict, standalone functions rarely rely on `this`

const counter = {
  count: 0,
  increment() {
    this.count++;          // this = counter (call-site object)
    return this.count;
  },
};

counter.increment();       // 1 — implicit binding
counter.increment();       // 2

// Nested: only the immediate call-site object matters
const outer = { inner: counter };
outer.inner.increment();   // this = inner (not outer)

function greet(greeting: string) {
  return `${greeting}, ${this.name}`;
}

const user = { name: 'Deiva' };

greet.call(user, 'Hello');         // "Hello, Deiva"
greet.apply(user, ['Hi']);         // "Hi, Deiva"

const boundGreet = greet.bind(user);
boundGreet('Hey');                 // "Hey, Deiva" — always user
boundGreet.call({ name: 'X' }, 'Try');  // still "Try, Deiva" — bind wins

function Animal(name: string) {
  this.name = name;          // this = new object
  this.speak = function() {
    return `${this.name} speaks`;
  };
}

const cat = new Animal('Cat');
cat.speak();                 // "Cat speaks"

// TypeScript classes use the same new binding under the hood
class Dog {
  constructor(public name: string) {}  // this.name = name
  speak() { return `${this.name} barks`; }
}
const dog = new Dog('Rex');  // new binding

class Timer {
  ticks = 0;

  start() {
    // Regular function — this would be lost:
    // setInterval(function() { this.ticks++; }, 1000); // BUG

    // Arrow function — this captured from start()'s scope (the Timer instance):
    setInterval(() => {
      this.ticks++;          // always Timer instance
    }, 1000);
  }
}

// Arrow also works for class fields (preferred in Angular):
class Btn {
  label = 'Click me';
  handleClick = () => {      // arrow class field
    console.log(this.label); // always the Btn instance
  };
}

class User {
  name = 'Deiva';

  greet() {
    return `Hello from ${this.name}`;
  }
}

const user = new User();

// Works — implicit binding
user.greet();                      // "Hello from Deiva"

// Bug — context lost when method is detached:
const fn = user.greet;
fn();                              // TypeError in strict mode (this is undefined)

// Same bug with event listeners:
document.addEventListener('click', user.greet);  // this = document element

class User {
  name = 'Deiva';

  // Arrow class field — this is always the User instance
  // regardless of how it's called
  greet = () => `Hello from ${this.name}`;
}

const user = new User();
const fn = user.greet;    // safe to detach
fn();                      // "Hello from Deiva" ✓
document.addEventListener('click', user.greet); // ✓

@Component({
  selector: 'app-counter',
  template: `
    <button (click)="increment()">+</button>
    <button (click)="decrement()">-</button>
    <span>{{ count }}</span>
  `,
})
export class CounterComponent {
  count = 0;

  // Regular methods are fine — Angular's template calls them via the component
  // instance, so implicit binding applies: this = CounterComponent instance
  increment() { this.count++; }
  decrement() { this.count--; }

  // Passing methods as callbacks to external APIs: use arrow class fields
  logChange = () => {         // arrow — this always CounterComponent
    console.log(this.count);
  };

  ngOnInit() {
    // ✓ Arrow: this captured from ngOnInit's scope (the component instance)
    setInterval(() => this.refresh(), 5000);

    // ✗ Regular: this would be undefined in strict mode
    // setInterval(function() { this.refresh(); }, 5000);
  }

  refresh() { /* ... */ }
}

@Injectable({ providedIn: 'root' })
export class DataService {
  private cache = new Map<string, unknown>();

  // Injected HttpClient — calling methods on it uses its own this (fine)
  constructor(private http: HttpClient) {}

  // Arrow fields used when passing service methods as callbacks
  handleError = (err: Error) => {
    console.error('DataService error:', err);  // this = DataService instance
    this.cache.clear();
  };

  fetchData(url: string) {
    return this.http.get(url).pipe(
      catchError(this.handleError)   // safe to pass as callback
    );
  }
}

@Component({ ... })
export class ItemsComponent {
  items: Item[] = [];

  loadItems() {
    this.http.get<Item[]>('/api/items').pipe(
      // ✓ Arrow — this.processItem is always the component instance's method
      map(items => items.map(i => this.processItem(i))),
      tap(items => { this.items = items; }),
    ).subscribe();
  }

  processItem(item: Item): Item {
    return { ...item, processed: true };
  }
}

interface User { name: string; age: number; }

// TypeScript enforces that greet is called with a User as `this`
function greet(this: User, greeting: string): string {
  return `${greeting}, ${this.name} (${this.age})`;
}

const user: User = { name: 'Deiva', age: 30 };

greet.call(user, 'Hello');   // OK
// greet.call({ name: 'X' }, 'Hi');   // Error: missing `age`

// Disallow `this` entirely in free functions:
function pureHelper(this: void, x: number): number {
  // this.anything  // Error — this is void
  return x * 2;
}

// Step 1: Was the function called with new?
const obj = new Foo();           // new binding → this = new object

// Step 2: Was the function called with call/apply/bind?
foo.call(ctx);                   // explicit → this = ctx
const b = foo.bind(ctx); b();    // bind → this = ctx (locked)

// Step 3: Was the function called via an object property?
obj.foo();                       // implicit → this = obj

// Step 4: None of the above?
foo();                           // default → global / undefined (strict)

// Special: Is it an arrow function?
const arrow = () => {};          // lexical → this captured at definition
// Rules 1-4 don't apply to arrow functions

class Animal {
  name: string;
  constructor(name: string) { this.name = name; }

  describe() {
    // this is the actual instance, not Animal.prototype
    return `I am ${this.name}`;
  }
}

class Dog extends Animal {
  breed: string;
  constructor(name: string, breed: string) {
    super(name);
    this.breed = breed;
  }
}

const rex = new Dog('Rex', 'Labrador');
rex.describe();   // "I am Rex" — this = rex, not Animal.prototype

class DebugExample {
  value = 42;

  brokenMethod() {
    console.log('this =', this);   // Add this line to diagnose
    return this.value;
  }
}

const ex = new DebugExample();

// Works:
ex.brokenMethod();                          // this = DebugExample { value: 42 }

// Broken:
const ref = ex.brokenMethod;
ref();                                      // this = undefined (strict mode)

// The log tells you immediately: when this is undefined, context was lost
